import{_ as e,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Cota OpenAI: Limites de 3h e 24h | opencode-mystatus","description":"Aprenda a consultar cotas de 3h e 24h do OpenAI. Interprete janelas principal e secundária, barras de progresso e tempos de redefinição para Plus, Team e Pro.","frontmatter":{"title":"Cota OpenAI: Limites de 3h e 24h | opencode-mystatus","sidebarTitle":"Cota OpenAI","subtitle":"Consulta de cota OpenAI: limites de 3 horas e 24 horas","description":"Aprenda a consultar cotas de 3h e 24h do OpenAI. Interprete janelas principal e secundária, barras de progresso e tempos de redefinição para Plus, Team e Pro.","tags":["OpenAI","consulta de cota","cota de API"],"prerequisite":["start-quick-start","start-understanding-output"],"order":1},"headers":[],"relativePath":"pt/vbgate/opencode-mystatus/platforms/openai-usage/index.md","filePath":"pt/vbgate/opencode-mystatus/platforms/openai-usage/index.md"}'),s={name:"pt/vbgate/opencode-mystatus/platforms/openai-usage/index.md"};function i(n,a,d,l,p,c){return t(),o("div",null,[...a[0]||(a[0]=[r(`<h1 id="consulta-de-cota-openai-limites-de-3-horas-e-24-horas" tabindex="-1">Consulta de cota OpenAI: limites de 3 horas e 24 horas <a class="header-anchor" href="#consulta-de-cota-openai-limites-de-3-horas-e-24-horas" aria-label="Permalink to &quot;Consulta de cota OpenAI: limites de 3 horas e 24 horas&quot;">​</a></h1><h2 id="o-que-voce-podera-fazer-apos-concluir" tabindex="-1">O que você poderá fazer após concluir <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-concluir" aria-label="Permalink to &quot;O que você poderá fazer após concluir&quot;">​</a></h2><ul><li>Usar <code>/mystatus</code> para consultar a cota de assinatura OpenAI Plus/Team/Pro</li><li>Entender as informações de limite de 3 horas e 24 horas na saída</li><li>Entender a diferença entre janela principal e janela secundária</li><li>Entender como lidar com a expiração de token</li></ul><h2 id="o-seu-problema-atual" tabindex="-1">O seu problema atual <a class="header-anchor" href="#o-seu-problema-atual" aria-label="Permalink to &quot;O seu problema atual&quot;">​</a></h2><p>As chamadas de API do OpenAI têm limites, após exceder serão temporariamente restritas o acesso. Mas você não sabe:</p><ul><li>Quanta cota ainda resta?</li><li>Qual janela de 3 horas e 24 horas está sendo usada?</li><li>Quando será redefinida?</li><li>Por que às vezes vê dados de duas janelas?</li></ul><p>Se essas informações não forem dominadas a tempo, podem afetar seu progresso em usar ChatGPT para escrever código ou fazer projetos.</p><h2 id="quando-usar-este-metodo" tabindex="-1">Quando usar este método <a class="header-anchor" href="#quando-usar-este-metodo" aria-label="Permalink to &quot;Quando usar este método&quot;">​</a></h2><p>Quando você:</p><ul><li>Precisa usar frequentemente a API OpenAI para desenvolvimento</li><li>Nota que as respostas ficaram lentas ou está sendo limitado</li><li>Quer entender a situação de uso de contas de equipe</li><li>Quer saber quando a cota será atualizada</li></ul><h2 id="ideia-principal" tabindex="-1">Ideia principal <a class="header-anchor" href="#ideia-principal" aria-label="Permalink to &quot;Ideia principal&quot;">​</a></h2><p>O OpenAI tem dois tipos de janelas de limitação de taxa para chamadas de API:</p><table tabindex="0"><thead><tr><th>Tipo de janela</th><th>Duração</th><th>Função</th></tr></thead><tbody><tr><td><strong>Janela principal</strong> (primary)</td><td>Retornado pelo servidor OpenAI</td><td>Evitar um grande número de chamadas em curto período</td></tr><tr><td><strong>Janela secundária</strong> (secondary)</td><td>Retornado pelo servidor OpenAI (pode não existir)</td><td>Evitar uso excessivo a longo prazo</td></tr></tbody></table><p>O mystatus consultará paralelamente essas duas janelas, exibindo各自的:</p><ul><li>Porcentagem usada</li><li>Barra de progresso de cota restante</li><li>Tempo até a redefinição</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>A duração da janela é retornada pelo servidor OpenAI, diferentes tipos de assinatura (Plus, Team, Pro) podem ser diferentes.</p></div><h2 id="siga-me" tabindex="-1">Siga-me <a class="header-anchor" href="#siga-me" aria-label="Permalink to &quot;Siga-me&quot;">​</a></h2><h3 id="passo-1-executar-comando-de-consulta" tabindex="-1">Passo 1: Executar comando de consulta <a class="header-anchor" href="#passo-1-executar-comando-de-consulta" aria-label="Permalink to &quot;Passo 1: Executar comando de consulta&quot;">​</a></h3><p>No OpenCode, digite <code>/mystatus</code>, o sistema consultará automaticamente a cota de todas as plataformas configuradas.</p><p><strong>O que você deve ver</strong>: Contém informações de cota de OpenAI, Zhipu AI, Z.ai, Copilot, Google Cloud e outras plataformas (dependendo de quais plataformas você configurou).</p><h3 id="passo-2-encontrar-a-secao-openai" tabindex="-1">Passo 2: Encontrar a seção OpenAI <a class="header-anchor" href="#passo-2-encontrar-a-secao-openai" aria-label="Permalink to &quot;Passo 2: Encontrar a seção OpenAI&quot;">​</a></h3><p>Na saída, encontre a seção <code>## OpenAI Account Quota</code>.</p><p><strong>O que você deve ver</strong>: Conteúdo semelhante ao seguinte:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3-hour limit</span></span>
<span class="line"><span>███████████████░░░░░░░░░ 60% remaining</span></span>
<span class="line"><span>Resets in: 2h 30m</span></span></code></pre></div><h3 id="passo-3-interpretar-informacoes-da-janela-principal" tabindex="-1">Passo 3: Interpretar informações da janela principal <a class="header-anchor" href="#passo-3-interpretar-informacoes-da-janela-principal" aria-label="Permalink to &quot;Passo 3: Interpretar informações da janela principal&quot;">​</a></h3><p><strong>Janela principal</strong> (primary_window) geralmente exibe:</p><ul><li><strong>Nome da janela</strong>: Como <code>3-hour limit</code> ou <code>24-hour limit</code></li><li><strong>Barra de progresso</strong>: Exibe visualmente a proporção de cota restante</li><li><strong>Porcentagem restante</strong>: Como <code>60% remaining</code></li><li><strong>Tempo de redefinição</strong>: Como <code>Resets in: 2h 30m</code></li></ul><p><strong>O que você deve ver</strong>:</p><ul><li>O nome da janela exibe a duração (3 horas / 24 horas)</li><li>Quanto mais cheia a barra de progresso, mais restante, mais vazia significa quase esgotada</li><li>O tempo de redefinição é contagem regressiva, quando chega a zero a cota será atualizada</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Se você ver a mensagem <code>Limit reached!</code>, isso indica que a cota da janela atual foi usada, precisa esperar a redefinição.</p></div><h3 id="passo-4-ver-janela-secundaria-se-houver" tabindex="-1">Passo 4: Ver janela secundária (se houver) <a class="header-anchor" href="#passo-4-ver-janela-secundaria-se-houver" aria-label="Permalink to &quot;Passo 4: Ver janela secundária (se houver)&quot;">​</a></h3><p>Se o OpenAI retornar dados da janela secundária, você verá:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>24-hour limit</span></span>
<span class="line"><span>████████████████████████████ 90% remaining</span></span>
<span class="line"><span>Resets in: 20h 45m</span></span></code></pre></div><p><strong>O que você deve ver</strong>:</p><ul><li>Janela secundária exibe outra dimensão de tempo da cota (geralmente 24 horas)</li><li>Pode ter porcentagem restante diferente da janela principal</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>A janela secundária é um pool de cota independente, a janela principal usada não afeta a janela secundária e vice-versa.</p></div><h3 id="passo-5-ver-tipo-de-assinatura" tabindex="-1">Passo 5: Ver tipo de assinatura <a class="header-anchor" href="#passo-5-ver-tipo-de-assinatura" aria-label="Permalink to &quot;Passo 5: Ver tipo de assinatura&quot;">​</a></h3><p>Na linha <code>Account</code> você pode ver o tipo de assinatura:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span>                                   ^^^^^</span></span>
<span class="line"><span>                                   Tipo de assinatura</span></span></code></pre></div><p><strong>Tipos de assinatura comuns</strong>:</p><ul><li><code>plus</code>: Assinatura pessoal Plus</li><li><code>team</code>: Assinatura de equipe/organização</li><li><code>pro</code>: Assinatura Pro</li></ul><p><strong>O que você deve ver</strong>:</p><ul><li>O tipo de sua conta é exibido entre parênteses após o e-mail</li><li>Diferentes tipos podem ter diferentes limites</li></ul><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de verificação ✅&quot;">​</a></h2><p>Verifique se você entendeu:</p><table tabindex="0"><thead><tr><th>Cenário</th><th>O que você deve ver</th></tr></thead><tbody><tr><td>Janela principal 60% restante</td><td>Barra de progresso aproximadamente 60% cheia, exibe <code>60% remaining</code></td></tr><tr><td>Redefinir após 2.5 horas</td><td>Exibe <code>Resets in: 2h 30m</code></td></tr><tr><td>Limite atingido</td><td>Exibe <code>Limit reached!</code></td></tr><tr><td>Tem janela secundária</td><td>Janela principal e secundária cada uma tem uma linha de dados</td></tr></tbody></table><h2 id="avisos-sobre-armadilhas" tabindex="-1">Avisos sobre armadilhas <a class="header-anchor" href="#avisos-sobre-armadilhas" aria-label="Permalink to &quot;Avisos sobre armadilhas&quot;">​</a></h2><h3 id="❌-operacao-errada-nao-atualizar-token-apos-expiracao" tabindex="-1">❌ Operação errada: Não atualizar token após expiração <a class="header-anchor" href="#❌-operacao-errada-nao-atualizar-token-apos-expiracao" aria-label="Permalink to &quot;❌ Operação errada: Não atualizar token após expiração&quot;">​</a></h3><p><strong>Fenômeno de erro</strong>: Ver a mensagem <code>⚠️ OAuth 授权已过期</code> (chinês) ou <code>⚠️ OAuth token expired</code> (inglês)</p><p><strong>Causa</strong>: O OAuth Token expirou (duração específica controlada pelo servidor), após expirar não é possível consultar a cota.</p><p><strong>Operação correta</strong>:</p><ol><li>Faça login novamente no OpenAI no OpenCode</li><li>O token será atualizado automaticamente</li><li>Execute <code>/mystatus</code> novamente para consultar</li></ol><h3 id="❌-operacao-errada-confundir-janela-principal-e-secundaria" tabindex="-1">❌ Operação errada: Confundir janela principal e secundária <a class="header-anchor" href="#❌-operacao-errada-confundir-janela-principal-e-secundaria" aria-label="Permalink to &quot;❌ Operação errada: Confundir janela principal e secundária&quot;">​</a></h3><p><strong>Fenômeno de erro</strong>: Pensar que há apenas uma janela de cota, resultando que a janela principal esgotada mas a secundária ainda em uso</p><p><strong>Causa</strong>: As duas janelas são pools de cota independentes.</p><p><strong>Operação correta</strong>:</p><ul><li>Preste atenção ao tempo de redefinição de cada janela</li><li>Janela principal redefinição rápida, secundária redefinição lenta</li><li>Aloque uso razoavelmente, evitando que uma janela fique excessiva por muito tempo</li></ul><h3 id="❌-operacao-errada-ignorar-id-da-conta-de-equipe" tabindex="-1">❌ Operação errada: Ignorar ID da conta de equipe <a class="header-anchor" href="#❌-operacao-errada-ignorar-id-da-conta-de-equipe" aria-label="Permalink to &quot;❌ Operação errada: Ignorar ID da conta de equipe&quot;">​</a></h3><p><strong>Fenômeno de erro</strong>: Assinatura Team exibe a situação de uso de outra pessoa</p><p><strong>Causa</strong>: Assinatura Team precisa passar o ID da conta de equipe, caso contrário pode estar consultando a conta padrão.</p><p><strong>Operação correta</strong>:</p><ul><li>Certifique-se de fazer login na conta de equipe correta no OpenCode</li><li>O token incluirá automaticamente <code>chatgpt_account_id</code></li></ul><h2 id="resumo-desta-secao" tabindex="-1">Resumo desta seção <a class="header-anchor" href="#resumo-desta-secao" aria-label="Permalink to &quot;Resumo desta seção&quot;">​</a></h2><p>O mystatus consulta a cota chamando a API oficial OpenAI:</p><ul><li>Suporta autenticação OAuth (Plus/Team/Pro)</li><li>Exibe janela principal e janela secundária (se existirem)</li><li>Barra de progresso visualiza a cota restante</li><li>Contagem regressiva exibe tempo de redefinição</li><li>Detecta automaticamente expiração de token</li></ul><h2 id="proxima-secao" tabindex="-1">Próxima seção <a class="header-anchor" href="#proxima-secao" aria-label="Permalink to &quot;Próxima seção&quot;">​</a></h2><blockquote><p>A próxima seção aprenderemos <strong><a href="./../zhipu-usage/">Consulta de cota Zhipu AI e Z.ai</a></strong>.</p><p>Você aprenderá:</p><ul><li>O que é limite de token de 5 horas</li><li>Como visualizar cota mensal de MCP</li><li>Aviso quando a taxa de uso exceder 80%</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do código-fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do código-fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código-fonte</strong></summary><blockquote><p>Data de atualização: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th><th>Número da linha</th></tr></thead><tbody><tr><td>Entrada de consulta de cota OpenAI</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L207-L236" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>207-236</td></tr><tr><td>Chamada de API OpenAI</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L132-L155" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>132-155</td></tr><tr><td>Formatação de saída</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L164-L194" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>164-194</td></tr><tr><td>Análise de token JWT</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L64-L73" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>64-73</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Verificação de expiração de token</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L216-L221" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>216-221</td></tr><tr><td>Definição de tipo OpenAIAuthData</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L28-L33" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>28-33</td></tr></tbody></table><p><strong>Constantes</strong>:</p><ul><li><code>OPENAI_USAGE_URL = &quot;https://chatgpt.com/backend-api/wham/usage&quot;</code>: API oficial de consulta de cota OpenAI</li></ul><p><strong>Funções principais</strong>:</p><ul><li><code>queryOpenAIUsage(authData)</code>: Função principal para consultar cota OpenAI</li><li><code>fetchOpenAIUsage(accessToken)</code>: Chama a API OpenAI</li><li><code>formatOpenAIUsage(data, email)</code>: Formata a saída</li><li><code>parseJwt(token)</code>: Analisa o token JWT (implementação não padrão da biblioteca)</li><li><code>getEmailFromJwt(token)</code>: Extrai o e-mail do usuário do token</li><li><code>getAccountIdFromJwt(token)</code>: Extrai o ID da conta de equipe do token</li></ul></details>`,70)])])}const h=e(s,[["render",i]]);export{m as __pageData,h as default};
